import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "How do you calculate take-home pay?", a: "Take-home pay is gross pay minus federal tax, state tax, Social Security, Medicare, and deductions such as 401k or insurance." },
  { q: "What is FICA tax?", a: "FICA is the payroll tax for Social Security and Medicare. Employees commonly pay 6.2% for Social Security and 1.45% for Medicare." },
  { q: "How do pre-tax deductions reduce your taxable income?", a: "Pre-tax deductions lower the income used to calculate some taxes, which can reduce federal and state income tax." },
  { q: "What is the difference between gross and net pay?", a: "Gross pay is earnings before deductions and taxes. Net pay is the amount you actually take home." },
  { q: "How do you increase your take-home pay?", a: "You can increase take-home pay by increasing gross income, adjusting deductions, reducing pre-tax benefits, or reviewing withholding choices." },
];

const money = (v: number, d = 2) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const pct = (v: number) => `${Number.isFinite(v) ? v.toFixed(2) : "0.00"}%`;
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
const stateRates: Record<string, number> = { CA: 0.06, TX: 0, FL: 0, NY: 0.055, PA: 0.0307, IL: 0.0495, WA: 0, AZ: 0.025 };
const standardDeduction: Record<string, number> = { Single: 14600, "Married Joint": 29200, "Married Separate": 14600, "Head of Household": 21900 };

function federalTax(taxable: number, status: string) {
  const single = [[11600, .10], [47150, .12], [100525, .22], [191950, .24], [243725, .32], [609350, .35], [Infinity, .37]];
  const joint = [[23200, .10], [94300, .12], [201050, .22], [383900, .24], [487450, .32], [731200, .35], [Infinity, .37]];
  const brackets = status === "Married Joint" ? joint : single;
  let tax = 0, last = 0;
  for (const [limit, rate] of brackets) {
    if (taxable > last) tax += (Math.min(taxable, limit) - last) * rate;
    last = limit;
  }
  return Math.max(0, tax);
}

function calculatePay(salary: number, frequency: string, status: string, state: string, allowances: number, k401: number, health: number) {
  const periods: Record<string, number> = { Monthly: 12, Biweekly: 26, Weekly: 52, Semimonthly: 24 };
  const pretax = k401 + health;
  const taxable = Math.max(0, salary - pretax - (standardDeduction[status] ?? 14600) - allowances * 500);
  const fed = federalTax(taxable, status);
  const stateTax = Math.max(0, (salary - pretax) * (stateRates[state] ?? 0.04));
  const social = Math.min(salary, 168600) * 0.062;
  const medicare = salary * 0.0145;
  const netAnnual = salary - pretax - fed - stateTax - social - medicare;
  const p = periods[frequency] ?? 12;
  return { gross: salary / p, fed: fed / p, stateTax: stateTax / p, social: social / p, medicare: medicare / p, deductions: pretax / p, net: netAnnual / p, effective: salary ? (salary - netAnnual) / salary * 100 : 0 };
}

export default function TakeHomePayCalculator() {
  useCurrencyVersion();
  const [salary, setSalary] = useState(60000);
  const [frequency, setFrequency] = useState("Monthly");
  const [status, setStatus] = useState("Single");
  const [state, setState] = useState("CA");
  const [allowances, setAllowances] = useState(0);
  const [k401, setK401] = useState(3000);
  const [health, setHealth] = useState(1200);
  const result = useMemo(() => calculatePay(salary, frequency, status, state, allowances, k401, health), [salary, frequency, status, state, allowances, k401, health]);
  const statuses = ["Single", "Married Joint", "Married Separate", "Head of Household"];

  return (
    <>
      <SEOHead title="Free Take-Home Paycheck Calculator Online - Calculate Your Net Pay After Tax Instantly | CalcHive" description="Free online take-home paycheck calculator. Calculate net pay after federal tax, state tax, Social Security and Medicare for any salary and filing status instantly. 100% free, no signup required." canonical="/take-home-pay-calculator" keywords="free take home pay calculator, paycheck calculator free online, net pay calculator free, after tax salary calculator free, how much do I take home calculator free" category="Financial Calculators" breadcrumbName="Free Take-Home Paycheck Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Take-Home Paycheck Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Estimate paycheck net pay after federal tax, state tax, FICA, and pre-tax deductions.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            <div><label className="text-sm font-semibold text-foreground block mb-2">Gross salary</label><input type="number" value={salary} onChange={(e) => setSalary(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Pay frequency</label><select value={frequency} onChange={(e) => setFrequency(e.target.value)} className={inputClass}><option>Monthly</option><option>Biweekly</option><option>Weekly</option><option>Semimonthly</option></select></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Filing status</label><select value={status} onChange={(e) => setStatus(e.target.value)} className={inputClass}>{statuses.map((s) => <option key={s}>{s}</option>)}</select></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">State</label><select value={state} onChange={(e) => setState(e.target.value)} className={inputClass}>{Object.keys(stateRates).map((s) => <option key={s}>{s}</option>)}</select></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Federal allowances</label><input type="number" value={allowances} onChange={(e) => setAllowances(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Annual 401k deduction</label><input type="number" value={k401} onChange={(e) => setK401(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Annual health insurance</label><input type="number" value={health} onChange={(e) => setHealth(Number(e.target.value))} className={inputClass} /></div>
          </div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Net Take-Home Pay</p><p className="text-5xl sm:text-6xl font-black text-white">{money(result.net)}</p></div>
          <div className="overflow-x-auto mt-5"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Paycheck Breakdown</caption><tbody className="divide-y divide-border">{[["Gross pay", result.gross], ["Federal tax", result.fed], ["State tax", result.stateTax], ["Social Security", result.social], ["Medicare", result.medicare], ["Pre-tax deductions", result.deductions], ["Net pay", result.net]].map(([label, value]) => <tr key={String(label)}><td className="py-2.5 px-3 font-semibold">{String(label)}</td><td className="py-2.5 px-3">{money(Number(value))}</td></tr>)}</tbody></table></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Your Take-Home Pay After All Taxes for Free</h2><p className="text-muted-foreground leading-relaxed">Subtract payroll taxes, income taxes, and deductions from gross pay to estimate your net paycheck.</p>
          <h2 className="text-2xl font-bold text-foreground">What Deductions Come Out of Your Paycheck</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Take-Home Pay on $60,000 Salary by Filing Status and State</caption><thead className="bg-muted/60"><tr>{["Filing Status", "Gross Monthly", "Federal Tax", "State Tax (CA)", "FICA", "Net Monthly", "Effective Rate"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{statuses.map((s) => { const r = calculatePay(60000, "Monthly", s, "CA", 0, 0, 0); return <tr key={s}><td className="py-2.5 px-3 font-semibold">{s}</td><td className="py-2.5 px-3">{money(r.gross)}</td><td className="py-2.5 px-3">{money(r.fed)}</td><td className="py-2.5 px-3">{money(r.stateTax)}</td><td className="py-2.5 px-3">{money(r.social + r.medicare)}</td><td className="py-2.5 px-3">{money(r.net)}</td><td className="py-2.5 px-3">{pct(r.effective)}</td></tr>; })}</tbody></table></div>
          <h2 className="text-2xl font-bold text-foreground">Free Net Pay Calculator for Every Filing Status</h2><p className="text-muted-foreground leading-relaxed">Use this paycheck calculator as a quick planning estimate. Exact withholding depends on payroll settings and current tax rules.</p>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/take-home-pay-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


